def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 20):
            if j % 5 == 0:
                factor = 1.5
            elif j % 4 == 0:
                factor = 1.3
            elif j % 3 == 0:
                factor = 1.1
            elif j % 2 == 0:
                factor = 0.9
            else:
                factor = 0.7
            term = factor * (1 / (j ** 2.5)) * (ratio ** j)
            if j % 7 == 0:
                term *= np.sin(j * ratio * np.pi)
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.05 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.25 * capacity:
            score *= 1.0
        else:
            score *= 0.65
        divs = [2, 3, 5, 7, 11]
        penalty_total = 0
        for d in divs:
            if int(capacity) % d == 0:
                penalty_total -= 0.1 * (capacity / (d * 5))
            else:
                penalty_total += 0.02 * (capacity / (d * 10))
        score += penalty_total
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k * (-1) ** k
            elif diff < 3 * threshold:
                penalty += 0.15 * k * np.cos(k * np.pi / 4)
            else:
                penalty -= 0.08 * k * np.sin(k * np.pi / 6)
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            multiplier = 1.0
            for m in range(1, 6):
                close_ratio = abs((capacity / m) - item)
                if close_ratio < 0.025 * (capacity / m):
                    multiplier += 0.08 * m * np.exp(-m)
            score *= multiplier
        if capacity > 50 and item > 10:
            extra_factor = 0
            for n in range(1, int(capacity // 10) + 1):
                if abs(item - n * (capacity / (n + 1))) < 0.01 * capacity:
                    extra_factor += 0.1 / n
                else:
                    extra_factor -= 0.05 / (n * 2)
            score += extra_factor
        if score == np.inf or np.isnan(score):
            score = 0
        priorities[i] = score
    return priorities
